#include<bits/stdc++.h>
using namespace std;
struct node
{
    int l,r,lson,rson,sum;
}a[10000010];
int root[200010],ans[200010],cnt,n,m,l[200010],r[200010],x[200010];
vector<int> v[200010];
int add(int &x,int pos,int val,int newl=0,int newr=200000)
{
    int now=++cnt;
    if(x==0)
    {
        a[x].l=newl;
        a[x].r=newr;
        a[x].lson=a[x].rson=0;
        a[x].sum=0;
    }
    a[now]=a[x];
    a[now].sum+=val;
    if(a[now].l==a[now].r)
    {
        return now;
    }
    int mid=(a[now].l+a[now].r)>>1;
    if(pos<=mid)
    {
        a[now].lson=add(a[x].lson,pos,val,newl,mid);
    }
    else
    {
        a[now].rson=add(a[x].rson,pos,val,mid+1,newr);
    }
    return now;
}
int query(int &u,int &v,int k,int l=0,int r=200000)
{
    if(l==r)
    {
        return l;
    }
    if(!u)
    {
        a[u].l=l;
        a[u].r=r;
        a[u].lson=a[u].rson=0;
        a[u].sum=0;
    }
    if(!v)
    {
        a[v].l=l;
        a[v].r=r;
        a[v].lson=a[v].rson=0;
        a[v].sum=0;
    }
    if(k>a[v].sum-a[u].sum)
    {
        return -1;
    }
    int sum=a[a[v].lson].sum-a[a[u].lson].sum;
    int mid=(l+r)>>1;
    if(k<=sum)
    {
        return query(a[u].lson,a[v].lson,k,l,mid);
    }
    else
    {
        return query(a[u].rson,a[v].rson,k-sum,mid+1,r);
    }
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d%d",&l[i],&r[i],&x[i]);
    }
    for(int i=1;i<=m;i++)
    {
        int x;
        scanf("%d",&x);
        v[x].push_back(i);
    }
    for(int i=1;i<=200000;i++)
    {
        root[i]=root[i-1];
        for(int j:v[i])
        {
            root[i]=add(root[i],j,1);
        }
    }
    for(int i=1;i<=n;i++)
    {
        int now=query(root[l[i]-1],root[r[i]],x[i]);
        // printf("i=%d now=%d\n",i,now);
        if(now!=-1)
        {
            ans[now]++;
        }
    }
    for(int i=1;i<=m;i++)
    {
        printf("%d\n",ans[i]);
    }
    return 0;
}
